import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { insureUserAccountActions } from '../actions';
import { insureUserAccountStrings } from '../config';
import { MyTable, MyDialog } from '../../../includes';
import { TableCell, Typography, Button } from '@material-ui/core';
import { Add } from '@material-ui/icons';
import PaymentForm from '../../Services/Cooperative/Subscriptions/PaymentInfo/PaymentForm';


const style = theme => ({
    root: {
    },
    cell : {
        padding : 5,
    },
    cellText : {
        fontSize : 12,
    }
})
class _Payments extends Component {
    constructor(props) {
        super(props);
        this.state = {
            lastId : null,
            rows : 20,
            newPaymentDialog : false,
        }
    }
    
    componentDidMount() {
        this.getPayments();
    }
    getPayments(){
        const {dispatch} = this.props;
        const {lastId, rows} = this.state;
        insureUserAccountActions.getMyPayments(lastId, rows)(dispatch);
    }
    cellMapFormat=props=>({row, cellMap})=>{
        const {classes} = this.props;
        switch(cellMap){
            case "approved" : return <TableCell className={classes.cell}>
                <Typography className={classes.cellText}>{row.expDate ? "Approved" : null}</Typography>
            </TableCell>
            case "expDate" : return <TableCell className={classes.cell}>
                <Typography className={classes.cellText}>{new Date(row[cellMap]).toLocaleDateString()}</Typography>
            </TableCell>
            default : return <TableCell className={classes.cell}>
                <Typography className={classes.cellText}>{row[cellMap]}</Typography>
            </TableCell>
        }
    }
    submitPaymentCallback(done, result){
        if(done) {
            this.getPayments();
            this.setState({newPaymentDialog: false});
        }
    }
    render() {
        const {
            classes,
            [insureUserAccountStrings.payments] : payments
        } = this.props;
        const {newPaymentDialog} = this.state;
        return (
            <div className={classes.root}>
                <Button variant="contained"
                    color="primary"
                    onClick={()=>this.setState({newPaymentDialog : true})}>
                        <Add/>New Payment
                    </Button>
                <MyTable
                    header={["ID", "Transaction ID", "Method", "Cat.", "Amount", "Approved", "Expiration"]}
                    dataMap={["_id", "transactionId", "method", "type", "amount", "approved", "expDate"]}
                    data={payments || []}
                    CellMap={this.cellMapFormat({})}
                    />
                <MyDialog 
                    open={newPaymentDialog}
                    close={()=>this.setState({newPaymentDialog : false})}>
                    <PaymentForm
                        submitPaymentCallback={this.submitPaymentCallback.bind(this)}/>
                </MyDialog>
            </div>
        );
    }
}


_Payments.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({insureUserAccountReducer}) => ({
    [insureUserAccountStrings.payments] :insureUserAccountReducer[insureUserAccountStrings.payments],
})


export const Payments = connect(mapStateToProps)(withStyles(style)(_Payments));
export {Payments as default}