import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {Link} from 'react-router-dom';
import {withStyles} from '@material-ui/core/styles';
import { insureUtilStrings, insureUtil, insureActions } from '../../../../utils';
import { Subheader, FormDisplay, formActions } from '../../../../../includes';
import { insureRouteNames } from '../../../../routeNames';
import { Button } from '@material-ui/core';
import { getFormDisplayData } from '../../../../../includes/Forms/FormDisplay/functions';
import { appActions, alertAction } from '../../../../../../actions';
import { insureServiceActions } from '../../../actions';
import { KnowledgeArea } from '../../../../Home/KnowledeArea';


const style = theme => ({
    
    submitBtn : {
        backgroundColor : insureUtil.getTheme().secondary,
        color : insureUtil.getTheme().white,
    }
})
class _PaymentForm extends Component {
    formName = "paymentInfo"
    componentDidMount() {
        const {
            dispatch,
            [insureUtilStrings.forms] : forms
        } = this.props;
        if(!forms) insureActions.getForms()(dispatch);
    }
    
    submitPayment(){
        const {dispatch, submitPaymentCallback} = this.props;
        const data = getFormDisplayData(this.formDisplayContext)((message, type)=>{
            appActions.showSnackbar(
                alertAction[type](message)
            )(dispatch);
        });
        const self = this;
        if(data.userid){
            if(!String(data.userid).trim()) delete data.userid;
            else data.userid = parseInt(data.userid);
        }
        if(data) insureServiceActions.submitPaymentInfo(data, (done, result, message)=>{
            if(done) {
                getFormDisplayData(self.formDisplayContext, (name, value, context)=>{
                    context.setState({data : {}});
                    return true;
                })();
                formActions.resetFormData(this.formName)(dispatch);
            }
            if(submitPaymentCallback)
                submitPaymentCallback(done, result, message);
        })(dispatch);
    }
    render() {
        const {
            classes,
            [insureUtilStrings.forms] : forms,
        } = this.props;
        let paymentInfoForm;
        if(forms){
            const formFilter = forms.getFirstObjectByPropValue("name", this.formName) || {};
            paymentInfoForm = formFilter.item;
        }
        return (
            <FormDisplay
                header="New Payment Form"
                formName={this.formName}
                getContext={context => this.formDisplayContext = context}
                formConfig={paymentInfoForm && paymentInfoForm.value}
                /* [
                    {name : "name", label : "Name", placeholder : "Name"},
                    {name : "phone", label : "Phone", placeholder : "Phone number"},
                    {name : "method", label : "Payment menthod", type : "radio", options : [
                        {_id : "transfer", name : "Transfer"},
                        {_id : "opay", name : "Opay"},
                        {_id : "cash", name : "Cash"},
                    ]},
                    {name : "duration", label :"Duration Type", type : "radio", options : [
                        {_id : "month", name : "Months"},
                        {_id : "year", name : "Year"}
                    ]},
                    {name : "months", label : "Starting Month", type : "select", options : [
                        {_id : 1, name : "January"},
                        {_id : 2, name : "February"},
                        {_id : 3, name : "March"},
                        {_id : 4, name : "April"},
                        {_id : 5, name : "May"},
                        {_id : 6, name : "June"},
                        {_id : 7, name : "July"},
                        {_id : 8, name : "August"},
                        {_id : 9, name : "September"},
                        {_id : 10, name : "October"},
                        {_id : 11, name : "November"},
                        {_id : 12, name : "December"}
                    ]},
                    {name : "amount", label : "Amount (N)", placeholder : "Amount", type : "number"},
                    {name : "transactionId", label : "Transaction Id", placeholder : "Transaction Id"},
                ]} */
                hooks={{
                    "months" : {
                        visibility : {
                            variables : {
                                state : {
                                    name : "duration",
                                    value : "month",
                                    path : ['data']
                                },
                                // props : {}
                            }
                        }
                    }
                }}
                footer={()=><div style={{marginTop : 20}}>
                    <Button 
                        className={classes.submitBtn} 
                        onClick={this.submitPayment.bind(this)}
                        variant="contained">Submit Payment</Button>
                </div>}
                />
        );
    }
}


_PaymentForm.propTypes = {
    classes : PropTypes.object.isRequired,
    submitPaymentCallback : PropTypes.func,
};
const mapStateToProps = ({insureUtilReducer}) => ({
    [insureUtilStrings.forms] : insureUtilReducer[insureUtilStrings.forms],
})


export const PaymentForm = connect(mapStateToProps)(withStyles(style)(_PaymentForm));
export {PaymentForm as default}