import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Grid, Typography } from '@material-ui/core';
import SideMenu from './SideMenu/SideMenu';
import { insureUtilStrings, insureUtil } from '../utils';
import Cooperative from './Cooperative/Cooperative';
import { Payments } from './Payments';
import { insureUserAccountActions } from './actions';
import { insureUserAccountStrings } from './config';


const style = theme => ({
    root: {
        margin : 10,
        marginTop : 50,
    },
})
class _UserAccount extends Component {
    constructor(props) {
        super(props);
        this.state = {
            setSelectedItem : null
        }
    }
    componentDidMount() {
        this.getCooperativeInfo();
    }
    getCooperativeInfo(){
        const {dispatch} = this.props;
        insureUserAccountActions.getCooperativeInfo()(dispatch);
    }
    render() {
        const {
            classes,
            [insureUtilStrings.myProfile] : myProfile,
            [insureUserAccountStrings.cooperativeInfo] : coopInfo
        } = this.props;
        const {name} = myProfile || {};
        const {selectedMenu} = this.state;
        return (
            <div className={classes.root}>
                <Grid container spacing={2}>
                    <Grid item xs={12} sm={3} md={3} lg={3} xl={3}>
                        <SideMenu
                            menu={[
                                {name : "Cooperative", value : "coop"},
                                {name : "Payments", value : "payment"},
                                // {name : "My Profile", value : "propfile"},
                            ]}
                            setSelectedItem={selectedMenu=>this.setState({selectedMenu})}
                            />
                    </Grid>
                    <Grid item xs={12} sm={9} md={9} lg={9} xl={9}>
                        <div className={classes.header}>
                            <Typography paragraph style={{
                                color : insureUtil.getTheme().primary,
                                fontWeight : "bold"
                            }} variant="h4">{name}</Typography>
                            <Typography style={{color : "gray"}}>
                                Status : <span>
                                    {coopInfo && (coopInfo.suspended ? 
                                    "Suspended" : 
                                    (coopInfo.expDate && new Date(coopInfo.expDate) > new Date() ?
                                    "Active" : "Inactive")
                                )}</span>
                            </Typography>
                        </div>
                        <div style={{marginTop : 20}}>
                            {selectedMenu && (
                                (selectedMenu.value === "coop" && <Cooperative/>) ||
                                (selectedMenu.value === "payment" && <Payments/>)
                            )}
                        </div>
                    </Grid>
                </Grid>
            </div>
        );
    }
}


_UserAccount.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({insureUtilReducer, insureUserAccountReducer}) => ({
    [insureUtilStrings.myProfile] : insureUtilReducer[insureUtilStrings.myProfile],
    [insureUserAccountStrings.cooperativeInfo] : insureUserAccountReducer[insureUserAccountStrings.cooperativeInfo],
})


export const UserAccount = connect(mapStateToProps)(withStyles(style)(_UserAccount));
export {UserAccount as default}