import React, { Component } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { insureUtil } from '../../utils';
import { Typography } from '@material-ui/core';


const style = theme => ({
    root: {
        border : "solid 1px " + insureUtil.getTheme().primary,
        borderRadius : 5,
    },
    text : {
        textDecoration : "none",
        color : insureUtil.getTheme().secondary,
        marginLeft : 10,
        "&:hover" : {
            cursor : "pointer",
        }
    },
    selectedText :{
        color : insureUtil.getTheme().primary,
        fontWeight : "bold",
    }
})
class _SideMenu extends Component {
    constructor(props) {
        super(props);
        const {menu, setSelectedItem} = props;
        this.state = {
            value : menu ? menu[0].value : null
        }
        if(setSelectedItem && menu) setSelectedItem(menu[0])
    }
    selectItem = item => () => {
        this.setState({value : item.value});
        const {setSelectedItem} = this.props;
        if(setSelectedItem) setSelectedItem(item);
    }
    render() {
        const {classes, menu} = this.props;
        const {value } = this.state;
        return (
            <div className={classes.root}>
                {menu && menu.map((item, index)=>{

                    return <Typography 
                        key={index}
                        onClick={this.selectItem(item)} 
                        className={classNames(classes.text, value === item.value && classes.selectedText)}
                        >
                            {item.name}
                        </Typography>
                })}
            </div>
        );
    }
}


_SideMenu.propTypes = {
    classes : PropTypes.object.isRequired,
    menu : PropTypes.array, 
    setSelectedItem : PropTypes.func,
};
const mapStateToProps = state => ({
    state
})


export const SideMenu = connect(mapStateToProps)(withStyles(style)(_SideMenu));
export {SideMenu as default}