import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { FormDisplay } from '../../../../includes';
import { Button, CircularProgress } from '@material-ui/core';
import { getFormDisplayData } from '../../../../includes/Forms/FormDisplay/functions';
import { appActions, alertAction } from '../../../../../actions';
import { insureUserAccountActions } from '../../actions';
const style = theme => ({
    root: {
        
    }
})
class _NextOfKinForm extends Component {
    constructor(props) {
        super(props);
        this.state = {
            loading : false
        }
    }
    createNK(){
        this.setState({loading : true});
        const {dispatch} = this.props;
        const {inputFieldContexes} = this.nextOfKinContext;
        const data = getFormDisplayData(this.nextOfKinContext)(
            (message, type)=>{
                appActions.showSnackbar(
                    alertAction[type](message)
                )(dispatch);
                return false;
            }
        )
        if(data) insureUserAccountActions.createNextOfKin(data, done=>{
            this.setState({loading : false});
            if(done) {
                getFormDisplayData(this.nextOfKinContext, (name, value, context)=>{
                    context.setState({data : {}})
                })();
            }
        })(dispatch);
    }
    render() {
        const {classes, editMode, formData} = this.props;
        const {loading} = this.state;
        return (
            <div className={classes.root}>
                <FormDisplay
                        formName="coopRegNK"
                        header="Next of Kin"
                        formConfig={[
                            {name : "lastName", placeholder : "Last name", label : "Last Name"},
                            {name : "firstName", placeholder : "First name", label : "First Name"},
                            {name : "address", placeholder : "Address", label : "Address"},
                            {name : "phone", placeholder : "Phone", label : "Phone"},
                            {name : "email", placeholder : "Email", label : "Email"},
                            {name : "relationship", placeholder : "Relationship", label : "Relationship"}
                        ]}
                        formData={formData}
                        getContext={context => this.nextOfKinContext = context}
                        footer={props=><div>
                            {editMode ? <Button
                                variant="contained" 
                                color="primary"
                                onClick={this.createNK.bind(this)}>
                                   {loading && <CircularProgress size={20}/>} Update Next of Kin
                                </Button> : 
                            <Button
                                variant="contained" 
                                color="primary"
                                onClick={this.createNK.bind(this)}>
                                    {loading && <CircularProgress size={20}/>} Create Next of Kin
                                </Button>}
                        </div>}/>
            </div>
        );
    }
}
_NextOfKinForm.propTypes = {
    classes : PropTypes.object.isRequired,
    editMode : PropTypes.bool,
    formData : PropTypes.object,
};
export const NextOfKinForm = withStyles(style)(_NextOfKinForm);