import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { insureUserAccountStrings } from '../config';
import { Typography, Button } from '@material-ui/core';
import { SimpleListBoard, FormDisplay } from '../../../includes';
import { insureUtil } from '../../utils';
import { Edit, Cancel } from '@material-ui/icons';
import CoopRegForm from '../../Services/Cooperative/CoopReg/CoopRegForm';
import { NextOfKinForm } from './NextOfKinForm';


const style = theme => ({
    root: {
    },
    textContainer : {
        display : "flex"
    },
    header : {
        color : insureUtil.getTheme().secondary
    },
    regFormContainer : {
        margin : 10,
        [theme.breakpoints.up("sm")] : {
            margin : 20,
        },
        [theme.breakpoints.up("md")] : {
            margin : "20px 100px",
        },
    },
    form : {
        [theme.breakpoints.up("sm")] : {
            margin : 0,
        },
        [theme.breakpoints.up("md")] : {
            margin : 0
        },
    }
})
class _Cooperative extends Component {
    constructor(props) {
        super(props);
        this.state = {
            profileEdit : false,
            nkEdit : false,
        }
    }
    
    nameMapper = name => {
        switch(name){
            case "lastName" : return "Last name";
            case "firstName" : return "First name";
            case "email" : return "Email";
            case "phone" : return "Phone";
            case "expDate" : return "Expiration";
            case "address" : return "Address";
            case "_id" : return "ID";
            case "relationship" : return "Relationship";
            default : return String(name).toUpperCase();
        }
    }
    valueMapper = (name, value) => {
        switch(name){
            case "_id" : return String(value).padStart(4, "0");
            case "expDate" : return new Date(value).toLocaleDateString();
            default : return value;
        }
    }
    render() {
        const {
            classes,
            [insureUserAccountStrings.cooperativeInfo] : profile
        } = this.props;
        const {profileEdit, nkEdit} = this.state;
        return (

            <div className={classes.regFormContainer}>
                {profileEdit ?
                    <Button
                        color="secondary"
                        variant="contained"
                        onClick={()=>this.setState({profileEdit: false})}>
                            <Cancel/> Cancel
                        </Button>: 
                    <Button
                        color="primary"
                        variant="contained"
                        onClick={()=>this.setState({profileEdit: true})}>
                            <Edit/> Edit
                    </Button> }
                {profileEdit ? 
                <CoopRegForm
                    classes={{
                        container : classes.form
                    }}
                    formData={profile || {}}
                    editMode/> :
                <SimpleListBoard
                    title="Cooperative Profile"
                    classes={{header : classes.header}}
                    data={profile}
                    nameMapper={this.nameMapper.bind(this)}
                    valueMapper={this.valueMapper.bind(this)}
                    skip={["nextOfKin"]}
                    />}
                {profile && profile.nextOfKin && !nkEdit ? 
                    <div style={{marginTop : 50}}>
                        <Button
                            color="primary"
                            variant="contained"
                            onClick={()=>this.setState({nkEdit: true})}>
                                <Edit/> Edit
                            </Button> 
                        <SimpleListBoard
                            title="Next of Kin"
                            classes={{header : classes.header}}
                            data={profile.nextOfKin}
                            nameMapper={this.nameMapper.bind(this)}
                            valueMapper={this.valueMapper.bind(this)}
                            skip={[]}
                            />
                    </div> :
                    <div style={{
                        marginTop : 50,
                    }}>
                        <Button
                            color="secondary"
                            variant="contained"
                            onClick={()=>this.setState({nkEdit: false})}>
                                <Cancel/> Cancel
                            </Button>
                        <NextOfKinForm
                            editMode={nkEdit}
                            formData={profile && profile.nextOfKin ? profile.nextOfKin : {}}
                            classes={{root : classes.form}}
                            dispatch={this.props.dispatch}/>
                    </div>}
            </div>
        );
    }
}


_Cooperative.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({insureUserAccountReducer}) => ({
    [insureUserAccountStrings.cooperativeInfo] : insureUserAccountReducer[insureUserAccountStrings.cooperativeInfo],
})


export const Cooperative = connect(mapStateToProps)(withStyles(style)(_Cooperative));
export {Cooperative as default}